52:   -->
53:   <script>
54:     // BootOverlay calls window.__bootComplete() when done
55:     declare global {
56:       interface Window {
57:         __bootComplete: () => void;
58:       }
59:     }
60: 
61:     window.__bootComplete = function () {
62:       const lid = document.getElementById('lid');
63:       const termMount = document.getElementById('terminal-mount');
64: 
65:       if (!lid || !termMount) return;
66: 
67:       // Open the lid (CSS animation)
68:       lid.classList.add('open');
69: 
70:       // After lid opens, show terminal
71:       lid.addEventListener(
72:         'animationend',
73:         () => {
74:           termMount.classList.add('visible');
75:           // Focus terminal for keyboard input
76:           const textarea = termMount.querySelector('.xterm-helper-textarea');
77:           if (textarea instanceof HTMLTextAreaElement) textarea.focus();
78:         },
79:         { once: true }
80:       );
