84:     if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
85:       const lid = document.getElementById('lid');
86:       const termMount = document.getElementById('terminal-mount');
87:       if (lid) lid.classList.add('open');
88:       if (termMount) termMount.classList.add('visible');
89:     }
