1: /**
2:  * ─────────────────────────────────────────────────────
3:  *  Terminal.tsx — Main React island wrapping xterm.js
4:  *
5:  *  Initializes an xterm.Terminal inside a DOM ref, loads
6:  *  FitAddon and WebLinksAddon, manages input buffering,
7:  *  command history, tab completion, and dispatches to
8:  *  the command interpreter.
9:  *
10:  *  Usage in Astro:
11:  *    <Terminal client:load onBoot={() => { ... }} />
12:  * ─────────────────────────────────────────────────────
13:  */
14: 
15: import { useEffect, useRef } from 'react';
16: import { Terminal as XTerm } from '@xterm/xterm';
17: import { FitAddon } from '@xterm/addon-fit';
18: import { WebLinksAddon } from '@xterm/addon-web-links';
19: import '@xterm/xterm/css/xterm.css';
20: 
21: import { CONFIG } from '../terminal/config';
22: import { amberTheme } from '../terminal/themes';
23: import { execute, getCompletions, getCwd } from '../terminal/commands';
24: import type { TerminalWriter } from '../terminal/commands';
25: import { getSeasonalGreeting } from '../terminal/easter';
26: 
27: /* ── ASCII art banner — compact version ────────────── */
28: const BANNER = [
29:   ' ╦╔═╗╔═╗╦  ',
30:   ' ║║ ║║╣ ║  ',
31:   ' ╚╝╚═╝╚═╝╚═╝',
32: ];
33: 
34: /** Maximum command history entries */
35: const MAX_HISTORY = 80;
36: 
37: /* ── Props ───────────────────────────────────────────── */
38: 
39: /** @interface TerminalProps */
40: export interface TerminalProps {
41:   /**
42:    * Called once the terminal is mounted and ready.
43:    * The page can use this to know the terminal is interactive.
44:    */
45:   onBoot?: () => void;
46: 
47:   /** Additional CSS class name for the mount container */
48:   className?: string;
49: }
50: 
51: /* ── Helpers ─────────────────────────────────────────── */
52: 
53: /**
54:  * Build the prompt string with ANSI colors.
55:  * Format: joel01010@portfolio:~$
56:  */
57: function buildPrompt(): string {
58:   const cwdPath = getCwd();
59:   return `\x1b[1;38;2;255;140;0m${CONFIG.handle.toLowerCase()}@${CONFIG.host}\x1b[0m:\x1b[38;2;255;208;96m${cwdPath}\x1b[0m$ `;
60: }
61: 
62: /**
63:  * Get a time-of-day greeting for the welcome message.
64:  */
65: function getTimeGreeting(): string {
66:   const hour = new Date().getHours();
67: 
68:   if (hour >= 5 && hour < 12) {
69:     return '☀️  Good morning! Ready to explore?';
70:   } else if (hour >= 12 && hour < 17) {
71:     return '🌤️  Good afternoon! Welcome aboard.';
72:   } else if (hour >= 17 && hour < 21) {
73:     return '🌅  Good evening! Nice to see you.';
74:   } else {
75:     return '🌙  Burning the midnight oil? Respect.';
76:   }
77: }
78: 
79: /* ── Component ───────────────────────────────────────── */
80: 
81: /**
82:  * Terminal — Full xterm.js terminal island.
83:  *
84:  * Handles:
85:  * - xterm initialization with amber CRT theme
86:  * - FitAddon for responsive resizing
87:  * - WebLinksAddon for clickable URLs
88:  * - Keystroke buffering, Enter, Backspace, arrows
89:  * - Command history (up/down, max 80 entries)
90:  * - Tab completion from command list
91:  * - FIGlet banner, welcome message, seasonal greeting
92:  * - Command dispatch to commands.ts interpreter
93:  */
94: export default function Terminal({ onBoot, className }: TerminalProps) {
95:   /** Ref for the DOM element where xterm mounts */
96:   const mountRef = useRef<HTMLDivElement>(null);
97: 
98:   /** Ref to persist the xterm instance across renders */
99:   const termRef = useRef<XTerm | null>(null);
100: 
101:   /**
102:    * Initialize xterm.js in useEffect (requires DOM).
103:    * Clean up on unmount.
104:    */
105:   useEffect(() => {
106:     const container = mountRef.current;
107:     if (!container) return;
108: 
109:     /* ── Create terminal instance ───────────────────── */
110:     const term = new XTerm({
111:       theme: amberTheme,
112:       fontFamily: "'Share Tech Mono', 'JetBrains Mono', 'Courier New', monospace",
113:       fontSize: 15,
114:       lineHeight: 1.3,
115:       cursorBlink: true,
116:       cursorStyle: 'block',
117:       allowTransparency: true,
118:       scrollback: 1000,
119:       convertEol: true,
120:     });
121: 
122:     termRef.current = term;
123: 
124:     /* ── Load addons ────────────────────────────────── */
125:     const fitAddon = new FitAddon();
126:     term.loadAddon(fitAddon);
127:     term.loadAddon(new WebLinksAddon());
128: 
129:     /* ── Mount to DOM ───────────────────────────────── */
130:     term.open(container);
131: 
132:     // Initial fit (slight delay to ensure container has dimensions)
133:     requestAnimationFrame(() => {
134:       fitAddon.fit();
135:     });
136: 
137:     /* ── Resize handler ─────────────────────────────── */
138:     const handleResize = () => {
139:       fitAddon.fit();
140:     };
141:     window.addEventListener('resize', handleResize);
142: 
143:     /* ── Input state ────────────────────────────────── */
144:     let inputBuffer = '';
145:     const history: string[] = [];
146:     let historyIndex = -1;
147:     let savedInput = ''; // save current input when browsing history
148:     let executing = false; // prevent input during async command execution
149: 
150:     /* ── Terminal writer for commands ────────────────── */
151:     const writer: TerminalWriter = {
152:       writeln: (text: string) => term.writeln(text),
153:       write: (text: string) => term.write(text),
154:       clear: () => {
155:         term.clear();
156:         term.write('\x1b[H'); // move cursor to top-left
157:       },
158:       terminal: term,
159:     };
160: 
161:     /* ── Print banner & welcome ─────────────────────── */
162:     term.writeln('');
163:     BANNER.forEach((line) => {
164:       term.writeln(`\x1b[38;2;255;102;0m${line}\x1b[0m`);
165:     });
166:     term.writeln('');
167:     term.writeln(`\x1b[1;38;2;255;176;0mWelcome to ${CONFIG.owner}'s CLI Portfolio\x1b[0m`);
168:     term.writeln(`\x1b[38;2;136;136;136mType \x1b[1;38;2;255;208;96mhelp\x1b[0;38;2;136;136;136m to see available commands.\x1b[0m`);
169: 
170:     // Seasonal greeting (e.g. Halloween, Christmas)
171:     const seasonal = getSeasonalGreeting();
172:     if (seasonal) {
173:       term.writeln(`\x1b[38;2;0;230;118m${seasonal}\x1b[0m`);
174:     }
175: 
176:     // Time-of-day greeting
177:     term.writeln(`\x1b[38;2;0;230;118m${getTimeGreeting()}\x1b[0m`);
178:     term.writeln('');
179: 
180:     // Write initial prompt
181:     term.write(buildPrompt());
182: 
183:     /* ── Clear the current line and rewrite ──────────── */
184:     function clearLine() {
185:       term.write('\r\x1b[K');
186:       term.write(buildPrompt());
187:     }
188: 
189:     /* ── Key handler ────────────────────────────────── */
190:     term.onData((data: string) => {
191:       // Block input while an async command is running
192:       if (executing) return;
193: 
194:       const code = data.charCodeAt(0);
195: 
196:       // ── Enter (CR or LF) ─────────────────────────
197:       if (data === '\r' || data === '\n') {
198:         term.writeln('');
199: 
200:         const trimmed = inputBuffer.trim();
201:         if (trimmed) {
202:           // Add to history (deduplicate consecutive)
203:           if (history.length === 0 || history[history.length - 1] !== trimmed) {
204:             history.push(trimmed);
205:             if (history.length > MAX_HISTORY) history.shift();
206:           }
207: 
208:           // Execute command (may be async)
209:           executing = true;
210:           const savedBuffer = inputBuffer;
211:           inputBuffer = '';
212:           historyIndex = -1;
213:           savedInput = '';
214: 
215:           Promise.resolve(execute(savedBuffer, writer)).then(() => {
216:             executing = false;
217:             term.write(buildPrompt());
218:           }).catch(() => {
219:             executing = false;
220:             term.write(buildPrompt());
221:           });
222:         } else {
223:           // Empty input, just print new prompt
224:           inputBuffer = '';
225:           historyIndex = -1;
226:           savedInput = '';
227:           term.write(buildPrompt());
228:         }
229:         return;
230:       }
231: 
232:       // ── Backspace (127 or \b) ─────────────────────
233:       if (code === 127 || data === '\b') {
234:         if (inputBuffer.length > 0) {
235:           inputBuffer = inputBuffer.slice(0, -1);
236:           term.write('\b \b');
237:         }
238:         return;
239:       }
240: 
241:       // ── Tab (completion) ──────────────────────────
242:       if (data === '\t') {
243:         const parts = inputBuffer.split(/\s+/);
244:         const partial = parts[parts.length - 1];
245: 
246:         if (partial) {
247:           const completions = getCompletions(partial);
248:           if (completions.length === 1) {
249:             const suffix = completions[0].slice(partial.length);
250:             inputBuffer += suffix + ' ';
251:             term.write(suffix + ' ');
252:           } else if (completions.length > 1) {
253:             term.writeln('');
254:             term.writeln(completions.join('  '));
255:             term.write(buildPrompt() + inputBuffer);
256:           }
257:         }
258:         return;
259:       }
260: 
261:       // ── Arrow keys (escape sequences) ─────────────
262:       if (data.startsWith('\x1b[')) {
263:         const arrow = data.slice(2);
264: 
265:         // Up arrow — previous history
266:         if (arrow === 'A') {
267:           if (history.length === 0) return;
268:           if (historyIndex === -1) {
269:             savedInput = inputBuffer;
270:             historyIndex = history.length;
271:           }
272:           if (historyIndex > 0) {
273:             historyIndex--;
274:             inputBuffer = history[historyIndex];
275:             clearLine();
276:             term.write(inputBuffer);
277:           }
278:           return;
279:         }
280: 
281:         // Down arrow — next history
282:         if (arrow === 'B') {
283:           if (historyIndex === -1) return;
284:           historyIndex++;
285:           if (historyIndex >= history.length) {
286:             historyIndex = -1;
287:             inputBuffer = savedInput;
288:             savedInput = '';
289:           } else {
290:             inputBuffer = history[historyIndex];
291:           }
292:           clearLine();
293:           term.write(inputBuffer);
294:           return;
295:         }
296: 
297:         // Left/Right arrows — ignore for now
298:         return;
299:       }
300: 
301:       // ── Ctrl+C ────────────────────────────────────
302:       if (code === 3) {
303:         term.writeln('^C');
304:         inputBuffer = '';
305:         historyIndex = -1;
306:         term.write(buildPrompt());
307:         return;
308:       }
309: 
310:       // ── Ctrl+L (clear screen) ────────────────────
311:       if (code === 12) {
312:         writer.clear();
313:         term.write(buildPrompt() + inputBuffer);
314:         return;
315:       }
316: 
317:       // ── Regular printable characters ──────────────
318:       if (code >= 32) {
319:         inputBuffer += data;
320:         term.write(data);
321:       }
322:     });
323: 
324:     /* ── Focus terminal on click ────────────────────── */
325:     container.addEventListener('click', () => {
326:       term.focus();
327:     });
328: 
329:     /* ── Signal boot complete ───────────────────────── */
330:     if (onBoot) {
331:       onBoot();
332:     }
333: 
334:     /* ── Cleanup on unmount ─────────────────────────── */
335:     return () => {
336:       window.removeEventListener('resize', handleResize);
337:       term.dispose();
338:       termRef.current = null;
339:     };
340:   }, []); // eslint-disable-line react-hooks/exhaustive-deps
341: 
342:   return (
343:     <div
344:       ref={mountRef}
345:       id="terminal-mount"
346:       className={className || ''}
347:       role="application"
348:       aria-label="Interactive CLI terminal"
349:     />
350:   );
351: }
