25: const BOOT_LINES: BootLine[] = [
26:   { text: 'BIOS v2.1 — Detecting hardware...',                cls: 'dim'  },
27:   { text: '[  OK  ] CPU: x86_64 cortex-A72 @ 2.4GHz',        cls: 'ok'   },
28:   { text: '[  OK  ] RAM: 16 GB DDR4',                          cls: 'ok'   },
29:   { text: '[  OK  ] Display: Amber CRT 680×440',               cls: 'ok'   },
30:   { text: '[  OK  ] Keyboard: Model M (vintage)',               cls: 'ok'   },
31:   { text: '',                                                    cls: ''     },
32:   { text: 'Loading CLI-OS kernel v4.2...',                      cls: 'info' },
33:   { text: `[  OK  ] Mounting /home/${CONFIG.owner.toLowerCase().replace(/\s+/g, '')}`, cls: 'ok' },
34:   { text: '[  OK  ] Importing skill-set modules...',            cls: 'ok'   },
35:   { text: `[  OK  ] Starting virtual host: ${CONFIG.host}`,    cls: 'ok'   },
36:   { text: '[  OK  ] Activating CRT scanline driver',            cls: 'ok'   },
37:   { text: '[  OK  ] Injecting personality matrix...',           cls: 'ok'   },
38:   { text: '[  OK  ] Spawning AI assistant (Ezra)',              cls: 'ok'   },
39:   { text: '',                                                    cls: ''     },
40:   { text: '[[  OK  ]] System ready.',                           cls: 'ok'   },
41: ];
42: 
43: /* ── Props ───────────────────────────────────────────── */
44: 
45: /* ── Component ───────────────────────────────────────── */
