47: /**
48:  * BootOverlay — calls window.__bootComplete() when the
49:  * boot sequence finishes. No props needed from Astro.
50:  */
51: export default function BootOverlay() {
52:   const overlayRef = useRef<HTMLDivElement>(null);
53:   const [active, setActive] = useState(false);
54: 
55:   const typewriteLine = useCallback(
56:     (container: HTMLDivElement, line: BootLine): Promise<void> => {
57:       return new Promise((resolve) => {
58:         const span = document.createElement('span');
59:         span.className = line.cls || '';
60:         container.appendChild(span);
61:         container.appendChild(document.createTextNode('\n'));
62: 
63:         const text = line.text;
64:         if (!text) { resolve(); return; }
65: 
66:         let charIndex = 0;
67:         let lastTime = 0;
68: 
69:         const step = (timestamp: number) => {
70:           if (!lastTime) lastTime = timestamp;
71:           if (timestamp - lastTime >= CONFIG.typeSpeed) {
72:             span.textContent += text[charIndex] || '';
73:             charIndex++;
74:             lastTime = timestamp;
75:           }
76:           if (charIndex < text.length) {
77:             requestAnimationFrame(step);
78:           } else {
79:             resolve();
80:           }
81:         };
82: 
83:         requestAnimationFrame(step);
84:       });
85:     },
86:     []
87:   );
88: 
89:   useEffect(() => {
90:     const overlay = overlayRef.current;
91:     if (!overlay) return;
92: 
93:     let cancelled = false;
94:     const sleep = (ms: number) =>
95:       new Promise<void>(res => {
96:         const id = setTimeout(res, ms);
97:         if (cancelled) clearTimeout(id);
98:       });
99: 
100:     async function runBoot() {
101:       setActive(true);
102:       await sleep(400);
103: 
104:       for (const line of BOOT_LINES) {
105:         if (cancelled) return;
106:         await typewriteLine(overlay!, line);
107:         await sleep(CONFIG.bootLineDelay);
108:       }
109: 
110:       await sleep(600);
111:       if (cancelled) return;
112: 
113:       // Fade out
114:       overlay!.classList.add('fade-out');
115:       await sleep(550);
116: 
117:       setActive(false);
118:       // Signal the page controller
119:       if (typeof window !== 'undefined' && window.__bootComplete) {
120:         window.__bootComplete();
121:       }
122:     }
123: 
124:     runBoot();
125: 
126:     return () => { cancelled = true; };
127:   }, [typewriteLine]);
128: 
129:   return (
130:     <div
131:       ref={overlayRef}
132:       id="boot-overlay"
133:       className={active ? 'active' : ''}
134:       role="status"
135:       aria-live="polite"
136:       aria-label="System boot sequence"
137:     />
138:   );
139: }
